INSERT INTO SENTINEL_DB.CLAIMS.CALL_TRANSCRIPTS
    (transcript_id, claim_no, customer_id, call_date, caller_type, transcript_text, sentiment, intent, duration_seconds, agent_id)
SELECT column1,column2,column3,column4::TIMESTAMP,column5,column6,column7,column8,column9,column10
FROM VALUES
('TR-001','CLM-00001','CUST-001','2023-06-16 10:30:00','CLAIMANT','Agent: Thank you for calling Sentinel Insurance. How can I help today? Customer: I was rear-ended at an intersection yesterday and need to file a claim. Agent: I am sorry to hear that. Are you injured? Customer: No, just shaken up. My bumper and trunk are pretty damaged though. Agent: Let me get your claim started right away. I will need some details about the accident.','NEUTRAL','FILE_CLAIM',380,'AGT-01'),
('TR-002','CLM-00002','CUST-002','2023-04-11 14:15:00','POLICYHOLDER','Agent: Good afternoon, Sentinel Insurance. Customer: Hi, I have a burst pipe situation and my basement is flooded. I need to know what my policy covers. Agent: I understand the urgency. Let me pull up your policy. Your home policy does cover sudden water damage including cleanup and restoration. Customer: What about the mold? Agent: Mold remediation is covered up to your policy limits. I will get an adjuster out to you within 24 hours.','NEGATIVE','FILE_CLAIM',450,'AGT-02'),
('TR-003','CLM-00003','CUST-003','2022-01-22 09:00:00','CLAIMANT','Agent: Sentinel Insurance, how may I assist you? Customer: My car was stolen from the parking garage last night. I already filed a police report. Agent: I am very sorry. That must be stressful. Let me start your theft claim immediately. Do you have the police report number? Customer: Yes, it is PR-2022-04518. Agent: Perfect. We will begin processing this right away.','NEGATIVE','FILE_CLAIM',320,'AGT-03'),
('TR-004','CLM-00004','CUST-004','2023-08-10 11:00:00','THIRD_PARTY','Agent: Sentinel Insurance claims department. Customer: I am calling about an incident at a store. I slipped on a wet floor and injured my knee. Agent: I am sorry about your injury. Can you tell me which location this occurred at? Customer: It was the Main Street location last Saturday. Agent: I will connect you with our commercial claims adjuster who handles liability cases.','FRUSTRATED','FILE_CLAIM',290,'AGT-04'),
('TR-005','CLM-00001','CUST-001','2023-07-05 15:45:00','CLAIMANT','Agent: Sentinel Insurance, how can I help? Customer: I am calling to check on my auto claim CLM-00001. It has been almost three weeks. Agent: Let me check the status for you. I see your claim is still open and the adjuster has approved the repair estimate. Customer: When will I get my payment? Agent: The payment was processed yesterday and should arrive within 3-5 business days. Customer: Finally. Thank you.','FRUSTRATED','CLAIM_STATUS',260,'AGT-01'),
('TR-006','CLM-00006','CUST-006','2023-09-19 08:30:00','CLAIMANT','Agent: Good morning, Sentinel Insurance. Customer: One of our employees fell from a ladder yesterday and is in the hospital. We need to file a workers comp claim. Agent: I understand. Let me get the details. What is the employees name and your policy number? Customer: Policy is POL-0006. The employee is James Rodriguez. Agent: I am opening the claim now. An adjuster will reach out within 24 hours to discuss next steps.','NEGATIVE','FILE_CLAIM',410,'AGT-05'),
('TR-007','CLM-00010','CUST-010','2023-08-01 13:00:00','THIRD_PARTY','Agent: Claims department, how can I help? Customer: I purchased a product from one of your insured businesses and it malfunctioned causing injury. Agent: I am sorry to hear that. This would fall under product liability. Can you provide the business name and details of the incident? Customer: Yes, the product was a power tool purchased from Smith Industrial Supply. Agent: I will need to transfer you to our investigation unit for this type of claim.','FRUSTRATED','FILE_CLAIM',350,'AGT-06'),
('TR-008','CLM-00005','CUST-005','2024-01-10 10:00:00','CLAIMANT','Agent: Sentinel Insurance. Customer: I need an update on claim CLM-00005. It has been over a month and I have not heard anything. Agent: Let me review your file. I see the claim is still pending review. The adjuster needs additional documentation from you. Customer: Nobody told me that! What do you need? Agent: We need the medical report from your treating physician and photos of the walkway. Customer: This is ridiculous. I will send them today.','FRUSTRATED','CLAIM_STATUS',380,'AGT-02'),
('TR-009','CLM-00012','CUST-012','2023-06-01 09:30:00','POLICYHOLDER','Agent: Good morning. Customer: Hi, I am checking on my roof claim from the storm. Claim number CLM-00012. Agent: I have good news. Your claim has been approved and the payment of $7,850 was issued yesterday. Customer: That is great news! How do I find a contractor? Agent: We have a preferred vendor network. I can email you a list of approved roofing contractors in your area. Customer: That would be wonderful, thank you!','POSITIVE','CLAIM_STATUS',280,'AGT-03'),
('TR-010','CLM-00018','CUST-018','2024-02-08 16:00:00','POLICYHOLDER','Agent: Sentinel Insurance claims. Customer: We had a fire in our commercial kitchen and I need to know about business interruption coverage. Agent: I see you have claim CLM-00018 already filed. Your commercial policy includes business interruption coverage up to 12 months of lost revenue. Customer: How quickly can we get interim payments? We have employees to pay. Agent: I will escalate this to our commercial claims team. They can set up interim payments within 5 business days.','NEGATIVE','PAYMENT_INQUIRY',420,'AGT-04'),
('TR-011','CLM-00020','CUST-020','2024-02-02 11:15:00','CLAIMANT','Agent: Claims department. Customer: A tree fell on my roof during the storm last week. The damage is extensive and I cannot stay in the house. Agent: I am sorry about your situation. Your home policy includes additional living expenses coverage while your home is being repaired. Customer: How much does that cover? Agent: Up to $30,000 for temporary housing, meals, and related expenses. I will have our adjuster contact you today.','NEGATIVE','FILE_CLAIM',340,'AGT-05'),
('TR-012','CLM-00025','CUST-025','2024-03-01 14:30:00','CLAIMANT','Agent: How can I assist you today? Customer: I was rear-ended two weeks ago and my back is killing me. I need to add medical to my claim CLM-00025. Agent: I see your claim is currently for vehicle damage only. I can add a bodily injury component. Customer: Yes, please. My doctor says I need physical therapy. Agent: I will update the claim and have a medical claims adjuster reach out to discuss your treatment plan.','NEGATIVE','CLAIM_STATUS',310,'AGT-06'),
('TR-013','CLM-00031','CUST-001','2024-03-05 09:00:00','POLICYHOLDER','Agent: Sentinel Insurance. Customer: Hi, my fence was destroyed in that windstorm last week. I already have claim CLM-00031 open. I need to know if I should go ahead with repairs. Agent: I see your claim is open. Please wait for the adjuster inspection before beginning any permanent repairs. You can do temporary measures to prevent further damage. Customer: OK, the adjuster is coming Thursday. Agent: Correct. After their visit, you should have an answer within 48 hours.','NEUTRAL','CLAIM_STATUS',220,'AGT-01'),
('TR-014','CLM-00035','CUST-005','2023-02-05 10:30:00','POLICYHOLDER','Agent: Claims department, how can I help? Customer: My water heater burst and my basement is a mess. Do I need to hire a specific restoration company? Agent: You can use any licensed contractor, but our preferred vendors are pre-approved and can bill us directly. Customer: That would make things easier. Can you send me the list? Agent: Absolutely, I will email it right now along with your claim reference number CLM-00035.','NEUTRAL','DOCUMENT_REQUEST',250,'AGT-02'),
('TR-015','CLM-00038','CUST-033','2024-01-12 08:45:00','POLICYHOLDER','Agent: Good morning. Customer: We had an employee burn incident in our kitchen. I have the claim filed but I am getting pushback on the medical bills. Agent: Let me look at CLM-00038. I see the medical reserves are set. What specific bills are you having issues with? Customer: The specialist consultation was denied. Agent: I see that note. It appears we need additional documentation from the treating physician. I will have the adjuster call you today to sort this out.','FRUSTRATED','DISPUTE',380,'AGT-03'),
('TR-016','CLM-00040','CUST-035','2024-02-15 13:00:00','THIRD_PARTY','Agent: Sentinel Insurance. Customer: I slipped and fell at a restaurant and I want to file a claim against their insurance. Agent: I understand. Do you know if the restaurant is insured with us? Customer: Yes, they gave me your information. My medical bills are over $8,000. Agent: I will open a third-party claim. You will need to provide your medical records and bills. An investigator may also contact you.','NEGATIVE','FILE_CLAIM',330,'AGT-04'),
('TR-017','CLM-00045','CUST-040','2024-03-25 11:00:00','POLICYHOLDER','Agent: Claims department. Customer: I have a hail damage claim on my house, CLM-00045. The roofer gave me a much higher estimate than your adjuster. Agent: I understand the concern. You have the right to get a second opinion. Would you like us to send a senior adjuster for a re-inspection? Customer: Yes, please. The difference is almost $5,000. Agent: I will schedule that for early next week. Please have your contractor available to walk the roof with our adjuster.','FRUSTRATED','DISPUTE',350,'AGT-05'),
('TR-018','CLM-00047','CUST-042','2024-02-01 09:15:00','CLAIMANT','Agent: Sentinel Insurance claims. Customer: My car was stolen two weeks ago and I have not heard anything. Claim is CLM-00047. Agent: I see the claim is open and we are waiting on the police investigation update. Theft claims typically take 30 days to settle. Customer: 30 days?! I need a car now. Agent: Your policy includes rental car coverage. I will authorize a rental through our partner immediately. Customer: OK, that helps. Thank you.','FRUSTRATED','CLAIM_STATUS',290,'AGT-06'),
('TR-019','CLM-00054','CUST-049','2024-02-12 14:00:00','CLAIMANT','Agent: How can I help? Customer: I was injured by a machine at work and my workers comp claim CLM-00054 was filed. When will I start getting disability payments? Agent: Let me check. Your claim is approved and the first payment should process this Friday. Customer: Will it be the full amount? Agent: Yes, temporary total disability at two-thirds of your average weekly wage as per state guidelines.','NEUTRAL','PAYMENT_INQUIRY',260,'AGT-01'),
('TR-020','CLM-00065','CUST-015','2024-02-05 15:30:00','POLICYHOLDER','Agent: Sentinel Insurance. Customer: We had a warehouse fire and the damages are massive. I need to understand my commercial coverage limits. Agent: I see claim CLM-00065. Your policy has $2.5 million coverage limit. Current reserves are set at $160,000 but that may increase. Customer: It will definitely increase. We lost a lot of inventory. Agent: The adjuster is scheduled for a full assessment next Monday. We will have a better picture after that.','NEGATIVE','CLAIM_STATUS',400,'AGT-02'),
('TR-021','CLM-00073','CUST-023','2024-04-01 10:00:00','POLICYHOLDER','Agent: Claims department. Customer: My sump pump failed during the heavy rain and my finished basement is completely flooded. Agent: I am sorry to hear that. That is covered under your home policy. I see CLM-00073 is already filed. Customer: Yes, I need to know if the waterproofing work is covered too. Agent: Yes, preventive waterproofing to avoid future occurrences is included up to your policy limits. The adjuster will confirm the exact coverage during inspection.','NEGATIVE','CLAIM_STATUS',300,'AGT-03'),
('TR-022','CLM-00076','CUST-026','2024-04-02 08:30:00','POLICYHOLDER','Agent: Good morning, Sentinel Insurance. Customer: Lightning struck our house last night. There is fire damage to the roof and attic. Claim is CLM-00076. Agent: That sounds very serious. Is everyone safe? Customer: Yes, everyone is fine. We are staying at a hotel. Agent: Good. Your policy covers hotel and living expenses. I will fast-track the adjuster assignment given the severity.','NEGATIVE','FILE_CLAIM',280,'AGT-04'),
('TR-023','CLM-00082','CUST-004','2024-03-18 16:30:00','THIRD_PARTY','Agent: Claims department. Customer: I tripped over a merchandise display at one of your insured stores and hurt my ankle. Agent: I am sorry about your injury. Can you tell me which store and when this happened? Customer: It was March 15th at the downtown location. Agent: I see we have claim CLM-00082 filed. A liability adjuster will contact you within 48 hours to discuss your medical expenses and next steps.','NEGATIVE','CLAIM_STATUS',270,'AGT-05'),
('TR-024','CLM-00002','CUST-002','2023-05-15 11:00:00','POLICYHOLDER','Agent: Sentinel Insurance. Customer: I am calling about the final payment on my water damage claim CLM-00002. The restoration is complete. Agent: Let me check. I see the claim is now closed and the final payment of $4,100 for the mold remediation was sent last week. Customer: I received the other payments but not that one yet. Agent: It was mailed on May 10th. Please allow a few more business days. If you do not receive it by Friday, call us back.','NEUTRAL','PAYMENT_INQUIRY',240,'AGT-06'),
('TR-025','CLM-00088','CUST-020','2024-04-03 09:45:00','POLICYHOLDER','Agent: How can I help you today? Customer: Our grill was too close to the house and caught the siding on fire. I feel terrible about it. Agent: The important thing is everyone is safe. Accidental fires are covered under your home policy. Customer: Even if it was our fault? Agent: Yes, this type of accidental fire is a covered peril. I see CLM-00088 is filed and an adjuster will be out tomorrow.','NEUTRAL','FILE_CLAIM',310,'AGT-01'),
('TR-026','CLM-00090','CUST-025','2024-04-01 14:00:00','CLAIMANT','Agent: Claims department. Customer: My stolen car was found but it has been completely stripped. I want to know what happens now with CLM-00090. Agent: I understand your frustration. The investigation team needs to assess the vehicle to determine if it is a total loss or repairable. Customer: It is clearly totaled. There is nothing left. Agent: I understand, but we do need the formal assessment. I will request it be expedited.','FRUSTRATED','CLAIM_STATUS',320,'AGT-02'),
('TR-027','CLM-00008','CUST-008','2021-12-05 10:00:00','POLICYHOLDER','Agent: Sentinel Insurance. Customer: I want to dispute the denial of my kitchen fire claim CLM-00008. Agent: I see the claim was denied. Let me review the reason. It appears the investigation found the fire resulted from a code violation in the kitchen wiring. Customer: That wiring was there when we bought the house! Agent: I understand your position. You have the right to appeal. I can transfer you to our appeals department or you can submit a written appeal within 60 days.','FRUSTRATED','DISPUTE',390,'AGT-03'),
('TR-028','CLM-00052','CUST-047','2024-03-28 11:30:00','CLAIMANT','Agent: How may I assist you? Customer: I had a minor parking lot accident and filed CLM-00052. Just checking when the repair estimate will be done. Agent: The estimate was completed yesterday. Your vehicle has $2,800 in damage. Since your deductible is $500, we will cover $2,300. Customer: That sounds about right. When can I take it to the shop? Agent: Any time. I will email you the approved estimate and our preferred shop list.','POSITIVE','CLAIM_STATUS',230,'AGT-04'),
('TR-029','CLM-00079','CUST-029','2024-02-25 15:00:00','THIRD_PARTY','Agent: Sentinel Insurance claims. Customer: One of your insured delivery trucks damaged our loading dock. We need this repaired immediately. Agent: I understand the urgency. I see claim CLM-00079 is filed and under review. Customer: Under review? There is security camera footage clearly showing the incident. Agent: I will note that evidence is available. The adjuster will contact you within 24 hours to arrange an inspection and review the footage.','FRUSTRATED','CLAIM_STATUS',300,'AGT-05'),
('TR-030','CLM-00099','CUST-042','2024-04-07 10:15:00','CLAIMANT','Agent: Good morning, Sentinel Insurance. Customer: I was in a collision with a delivery van at an intersection. I just filed CLM-00099 online. Agent: I can see your claim. Are you injured? Customer: Minor neck pain. I am seeing my doctor today. Agent: Please keep all medical receipts and documentation. I will add a bodily injury note to your claim. Your adjuster will be ADJ-107 and they will call you within 24 hours. Customer: Thank you for the quick response.','NEUTRAL','FILE_CLAIM',270,'AGT-06');


select * from SENTINEL_DB.CLAIMS.CALL_TRANSCRIPTS;